con:configuration.scriptText:
import se.skl.rivta.tksupport.soapui.ContentAssertions def ca = new ContentAssertions(context, messageExchange, log)
def hsaIdPath = "/urn:healthcareFacilities/urn1:id" def validValues = [context.healthcareFacilityHSAId1, context.healthcareFacilityHSAId2] ca.assertValidValuesInAllRecords(hsaIdPath, validValues)
ca.assertSpecificValueInAnyRecord(hsaIdPath, validValues[0]) ca.assertSpecificValueInAnyRecord(hsaIdPath, validValues[1])

con:config.script:
import se.skl.rivta.testsupport.soapui.datasource.XmlDataReader
import com.eviware.soapui.support.GroovyUtils

def utils = new GroovyUtils(context)
def dataFile = new File(utils.projectPath + "/data.xml")
def source = new XmlDataReader(context, dataFile)

source.load(testRunner.testCase.getName())

con:configuration.scriptText:
import se.skl.rivta.tksupport.soapui.ContentAssertions def ca = new ContentAssertions(context, messageExchange, log) def typePath = "/urn:healthcareFacilities/urn1:supportedListingTypes/urn1:code" def typeCode = "PV"
def recordConstraint = { record -> record.allElementsAt(typePath).size() == 0 || record.allElementsAt(typePath).contains(typeCode) }
ca.assertForAllRecords(recordConstraint, "Expected listing type PV in all facilities")

